diff --git a/packages/babel-preset-babili/__tests__/options-tests.js b/packages/babel-preset-babili/__tests__/options-tests.js
index 696597e..2c83098 100644
--- a/packages/babel-preset-babili/__tests__/options-tests.js
+++ b/packages/babel-preset-babili/__tests__/options-tests.js
@@ -85,19 +85,23 @@ describe("preset-options", () => {

   it("should handle options that are delegated to multiple other options", () => {
     testOpts({
-      keepFnName: false
+      keepFnName: false,
+      keepClassName: false
     });
     testOpts({
       keepFnName: true,
+      keepClassName: true,
       mangle: {
         blacklist: ["foo", "bar"]
       }
     });
     testOpts({
       keepFnName: true,
+      keepClassName: true,
       mangle: {
         blacklist: ["baz"],
-        keepFnName: false
+        keepFnName: false,
+        keepClassName: false,
       }
     });
   });

