+    expect(minify(sampleInput, minifyOpts).code).toMatchSnapshot();
+  });
+
+  it("override nested minify options", () => {
+    const minifyOpts = { mangle: { keepFnName: false } };
+    expect(minify(sampleInput, minifyOpts).code).toMatchSnapshot();
+  });
+});

